mapper.update:
UPDATE hotel_kiosk.room_master m JOIN hotel_kiosk.room_status s
    ON m.room_no = s.room_no
SET room_name = #{roomName}, room_type = #{roomType}, room_view=#{roomView}, base_price = #{basePrice}, max_people = #{maxPeople}, bed_type = #{bedType}, rating = #{rating}, s.updated_at = localtime, m.updated_at = localtime, current_status = #{currentStatus}
WHERE m.room_no = #{roomNo}

UPDATE hotel_kiosk.room_status s join hotel_kiosk.room_master m ON s.room_no = m.room_no
SET current_status = #{currentStatus}, s.updated_at = localtime, m.updated_at = localtime
WHERE s.room_no = #{roomNo}

mapper.select:
SELECT base_price
FROM room_master
WHERE room_no = #{roomNo}
